// Helper functions



export async function fetchData<T>(url: string): Promise<T> {
  const response: Response = await fetch(url);
  if (!response.ok) {
    throw new Error('Network response was not ok');
  }
  const data: T = await response.json();
  return data;
}

export const isCorrectAns = (input1: string, input2: string) => {
  return input1.toLowerCase().trim() === input2.toLowerCase().trim();
};

export const archTypeProvider = (
  archetypeName: string,
  archetypeData: any[],
) =>  archetypeData.find(item => item?.name === archetypeName);
  